from smolagents import Tool
import httpx

class WeatherTool(Tool):
    name = "get_weather"
    description = "Get the current weather for a city."
    inputs = {
        "city": {
            "type": "string",
            "description": "The city name, e.g. 'Berlin'.",
        }
    }
    output_type = "string"

    def __init__(self, api_key: str):
        super().__init__()
        self._client = httpx.Client()
        self._api_key = api_key

    def forward(self, city: str) -> str:
        resp = self._client.get(
            "https://api.openweathermap.org/data/2.5/weather",
            params={"q": city, "appid": self._api_key, "units": "metric"},
        )
        data = resp.json()
        temp = data["main"]["temp"]
        desc = data["weather"][0]["description"]
        return f"{city}: {temp}C, {desc}"

agent = CodeAgent(
    tools=[WeatherTool(api_key="your-key")],
    model=HfApiModel("Qwen/Qwen2.5-Coder-32B-Instruct"),
)

result = agent.run("Calculate the sum of the squares of numbers 1 to 10.")
print(result)

# Inspect each step
for step in agent.logs:
    print("--- step ---")
    print(f"Thought: {step.agent_memory[-1].get('content', '')[:200]}")
    if hasattr(step, 'tool_calls'):
        for call in step.tool_calls:
            print(f"  Tool: {call.name}  |  Input: {call.arguments}")
